queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?podcasts a :Podcasts .
    ?podcasts p:Title ?title .
    ?podcasts p:Length ?length_f .
    FILTER((STR(?length_f) = "60" || STR(?length_f) = "60.0"))
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?audiodocuments a :AudioDocuments .
    ?audiodocuments p:Title ?title .
    ?audiodocuments p:Length ?length_f .
    FILTER((STR(?length_f) = "60" || STR(?length_f) = "60.0"))
    BIND(?title AS ?o0)
  }
}

